Here's a beautifully designed, self-contained HTML file that visually demonstrates NP-Completeness with exceptional aesthetics:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Visualizing NP-Completeness</title>
    <style>
        :root {
            --primary: #6c5ce7;
            --secondary: #a29bfe;
            --accent: #fd79a8;
            --dark: #2d3436;
            --light: #f5f6fa;
            --success: #00b894;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        body {
            background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);
            color: var(--dark);
            min-height: 100vh;
            overflow-x: hidden;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
            padding: 2rem;
        }

        header {
            text-align: center;
            margin-bottom: 3rem;
            animation: fadeIn 1.5s ease-out;
        }

        h1 {
            font-size: 3.5rem;
            font-weight: 800;
            background: linear-gradient(to right, var(--primary), var(--accent));
            -webkit-background-clip: text;
            background-clip: text;
            color: transparent;
            margin-bottom: 1rem;
            letter-spacing: -1px;
        }

        .subtitle {
            font-size: 1.2rem;
            color: var(--dark);
            opacity: 0.8;
            max-width: 700px;
            margin: 0 auto;
            line-height: 1.6;
        }

        .visualization {
            display: flex;
            flex-direction: column;
            gap: 3rem;
            margin-top: 4rem;
        }

        .concept-card {
            background: white;
            border-radius: 16px;
            box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08);
            padding: 2.5rem;
            transition: transform 0.4s ease, box-shadow 0.4s ease;
            position: relative;
            overflow: hidden;
        }

        .concept-card:hover {
            transform: translateY(-5px);
            box-shadow: 0 25px 50px rgba(0, 0, 0, 0.12);
        }

        .concept-card::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            width: 5px;
            height: 100%;
            background: linear-gradient(to bottom, var(--primary), var(--accent));
        }

        .card-header {
            display: flex;
            align-items: center;
            margin-bottom: 1.5rem;
        }

        .card-icon {
            width: 50px;
            height: 50px;
            background: linear-gradient(135deg, var(--primary), var(--secondary));
            border-radius: 12px;
            display: flex;
            align-items: center;
            justify-content: center;
            margin-right: 1.5rem;
            color: white;
            font-size: 1.5rem;
            box-shadow: 0 10px 20px rgba(108, 92, 231, 0.3);
        }

        .card-title {
            font-size: 1.8rem;
            font-weight: 700;
            color: var(--dark);
        }

        .card-content {
            line-height: 1.8;
            color: #555;
            margin-bottom: 2rem;
        }

        .graph-container {
            width: 100%;
            height: 400px;
            position: relative;
            margin: 2rem 0;
        }

        .graph {
            width: 100%;
            height: 100%;
            background: white;
            border-radius: 12px;
            position: relative;
            overflow: hidden;
        }

        .node {
            position: absolute;
            width: 50px;
            height: 50px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-weight: bold;
            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.1);
            transition: all 0.3s ease;
            cursor: default;
            z-index: 2;
        }

        .node:hover {
            transform: scale(1.1);
            box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);
        }

        .edge {
            position: absolute;
            height: 3px;
            background: var(--secondary);
            transform-origin: left center;
            z-index: 1;
        }

        .complexity-chart {
            width: 100%;
            height: 300px;
            margin-top: 2rem;
            position: relative;
        }

        .axis {
            position: absolute;
            background: var(--dark);
        }

        .x-axis {
            width: 100%;
            height: 2px;
            bottom: 0;
            left: 0;
        }

        .y-axis {
            width: 2px;
            height: 100%;
            bottom: 0;
            left: 50px;
        }

        .chart-line {
            position: absolute;
            height: 2px;
            background: var(--primary);
            transform-origin: left center;
        }

        .chart-label {
            position: absolute;
            font-size: 0.9rem;
            color: var(--dark);
            opacity: 0.8;
        }

        .button-container {
            display: flex;
            justify-content: center;
            gap: 1.5rem;
            margin-top: 3rem;
        }

        .btn {
            padding: 0.8rem 1.8rem;
            border-radius: 50px;
            font-weight: 600;
            border: none;
            cursor: pointer;
            transition: all 0.3s ease;
            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.1);
        }

        .btn-primary {
            background: linear-gradient(to right, var(--primary), var(--secondary));
            color: white;
        }

        .btn-outline {
            background: transparent;
            border: 2px solid var(--primary);
            color: var(--primary);
        }

        .btn:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);
        }

        .btn:active {
            transform: translateY(1px);
        }

        footer {
            text-align: center;
            margin-top: 5rem;
            padding: 2rem 0;
            color: #666;
            font-size: 0.9rem;
        }

        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(20px); }
            to { opacity: 1; transform: translateY(0); }
        }

        @keyframes pulse {
            0% { transform: scale(1); }
            50% { transform: scale(1.05); }
            100% { transform: scale(1); }
        }

        .pulse {
            animation: pulse 2s infinite;
        }

        .highlight {
            background: linear-gradient(to right, rgba(253, 121, 168, 0.2), transparent);
            padding: 0.2rem 0.5rem;
            border-radius: 4px;
        }
    </style>
</head>
<body>
    <div class="container">
        <header>
            <h1>NP-Completeness</h1>
            <p class="subtitle">A visual exploration of computational complexity and the fascinating boundary between tractable and intractable problems</p>
        </header>

        <div class="visualization">
            <div class="concept-card">
                <div class="card-header">
                    <div class="card-icon">P</div>
                    <h2 class="card-title">Polynomial Time Problems</h2>
                </div>
                <p class="card-content">
                    Problems that can be solved by a deterministic Turing machine in polynomial time (O(n<sup>k</sup>) for some constant k). 
                    These are considered <span class="highlight">"tractable"</span> as their running time grows at a manageable rate with input size.
                </p>
                <div class="complexity-chart">
                    <div class="axis x-axis"></div>
                    <div class="axis y-axis"></div>
                    <div class="chart-line" style="width: 100%; bottom: 50px; transform: rotate(-5deg);"></div>
                    <div class="chart-label" style="bottom: 20px; left: 50%; transform: translateX(-50%);">Input Size (n)</div>
                    <div class="chart-label" style="left: 30px; bottom: 50%; transform: rotate(-90deg) translateX(50%);">Time Complexity</div>
                    <div class="chart-label" style="left: 60%; top: 30%; color: var(--primary); font-weight: 600;">Polynomial Growth</div>
                </div>
            </div>

            <div class="concept-card">
                <div class="card-header">
                    <div class="card-icon">NP</div>
                    <h2 class="card-title">Nondeterministic Polynomial Time</h2>
                </div>
                <p class="card-content">
                    Problems whose solutions can be <span class="highlight">verified</span> in polynomial time by a deterministic Turing machine. 
                    This class includes all P problems and potentially others where finding the solution might be harder than verifying it.
                </p>
                <div class="graph-container">
                    <div class="graph" id="np-graph">
                        <!-- Nodes and edges will be added via JavaScript -->
                    </div>
                </div>
            </div>

            <div class="concept-card pulse">
                <div class="card-header">
                    <div class="card-icon" style="background: linear-gradient(135deg, var(--accent), #e84393);">NPC</div>
                    <h2 class="card-title">NP-Complete Problems</h2>
                </div>
                <p class="card-content">
                    The most fascinating class in computational complexity - problems that are in NP and to which every other NP problem can be 
                    <span class="highlight">reduced</span> in polynomial time. If any NP-complete problem has a polynomial-time solution, then P = NP.
                </p>
                <div class="graph-container">
                    <div class="graph" id="npc-graph">
                        <!-- Nodes and edges will be added via JavaScript -->
                    </div>
                </div>
            </div>

            <div class="concept-card">
                <div class="card-header">
                    <div class="card-icon" style="background: linear-gradient(135deg, var(--dark), #636e72);">P vs NP</div>
                    <h2 class="card-title">The Millennium Problem</h2>
                </div>
                <p class="card-content">
                    The question of whether P = NP is one of the most important unsolved problems in computer science, with a $1 million prize for its solution. 
                    Most researchers believe P ≠ NP, meaning that NP-complete problems are inherently difficult and no efficient algorithm exists for them.
                </p>
                <div class="complexity-chart" style="height: 400px;">
                    <div class="axis x-axis"></div>
                    <div class="axis y-axis"></div>
                    <div class="chart-line" style="width: 30%; bottom: 50px; transform: rotate(-5deg); background: var(--success);"></div>
                    <div class="chart-line" style="width: 100%; bottom: 150px; transform: rotate(-25deg); background: var(--accent); left: 30%;"></div>
                    <div class="chart-label" style="left: 15%; bottom: 70px; color: var(--success); font-weight: 600;">P Problems</div>
                    <div class="chart-label" style="left: 65%; bottom: 170px; color: var(--accent); font-weight: 600;">NP-Complete Problems</div>
                    <div class="chart-label" style="left: 40%; top: 50px; font-weight: 700; font-size: 1.2rem;">P ≠ NP ?</div>
                </div>
            </div>
        </div>

        <div class="button-container">
            <button class="btn btn-primary" id="show-examples">Show Classic Examples</button>
            <button class="btn btn-outline" id="learn-more">Learn More</button>
        </div>

        <footer>
            <p>Visualization of NP-Completeness | For educational purposes only</p>
            <p>© 2023 Computational Complexity Explorer</p>
        </footer>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            // Create NP graph visualization
            const npGraph = document.getElementById('np-graph');
            const npcGraph = document.getElementById('npc-graph');

            // Create nodes for NP graph
            const npNodes = [
                { id: 'p', label: 'P', x: 30, y: 50, color: 'var(--primary)' },
                { id: 'np', label: 'NP', x: 70, y: 50, color: 'var(--secondary)' }
            ];

            // Create nodes for NP-Complete graph
            const npcNodes = [
                { id: 'sat', label: 'SAT', x: 20, y: 30, color: 'var(--accent)' },
                { id: 'tsp', label: 'TSP', x: 50, y: 70, color: 'var(--accent)' },
                { id: 'clique', label: 'Clique', x: 80, y: 30, color: 'var(--accent)' },
                { id: 'vc', label: 'Vertex Cover', x: 50, y: 30, color: 'var(--accent)' }
            ];

            // Create edges for NP-Complete graph
            const npcEdges = [
                { from: 'sat', to: 'tsp' },
                { from: 'sat', to: 'clique' },
                { from: 'sat', to: 'vc' },
                { from: 'tsp', to: 'clique' },
                { from: 'vc', to: 'clique' }
            ];

            // Draw NP graph
            drawGraph(npGraph, npNodes, []);

            // Draw NP-Complete graph
            drawGraph(npcGraph, npcNodes, npcEdges);

            // Animate the graphs after a delay
            setTimeout(() => {
                animateGraph(npGraph);
                animateGraph(npcGraph);
            }, 1000);

            // Button interactions
            document.getElementById('show-examples').addEventListener('click', function() {
                alert('Classic NP-Complete problems:\n\n- Boolean satisfiability (SAT)\n- Traveling salesman (TSP)\n- Graph coloring\n- Knapsack problem\n- Hamiltonian path\n- Subset sum\n\nThese all share the fundamental property of NP-Completeness.');
            });

            document.getElementById('learn-more').addEventListener('click', function() {
                alert('To learn more about NP-Completeness:\n\n1. "Computers and Intractability" by Garey & Johnson\n2. "Introduction to the Theory of Computation" by Sipser\n3. Clay Mathematics Institute\'s Millennium Problems\n\nThis is one of the deepest questions in theoretical computer science!');
            });

            // Helper function to draw a graph
            function drawGraph(container, nodes, edges) {
                const width = container.clientWidth;
                const height = container.clientHeight;

                // Create edges first (so they appear behind nodes)
                edges.forEach(edge => {
                    const fromNode = nodes.find(n => n.id === edge.from);
                    const toNode = nodes.find(n => n.id === edge.to);

                    if (fromNode && toNode) {
                        const edgeEl = document.createElement('div');
                        edgeEl.className = 'edge';

                        // Calculate edge position and length
                        const x1 = (width * fromNode.x / 100) + 25;
                        const y1 = (height * fromNode.y / 100) + 25;
                        const x2 = (width * toNode.x / 100) + 25;
                        const y2 = (height * toNode.y / 100) + 25;

                        const length = Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2));
                        const angle = Math.atan2(y2 - y1, x2 - x1) * 180 / Math.PI;

                        edgeEl.style.width = `${length}px`;
                        edgeEl.style.left = `${x1}px`;
                        edgeEl.style.top = `${y1}px`;
                        edgeEl.style.transform = `rotate(${angle}deg)`;
                        edgeEl.style.opacity = '0';

                        container.appendChild(edgeEl);

                        // Animate edge appearance
                        setTimeout(() => {
                            edgeEl.style.opacity = '0.6';
                            edgeEl.style.transition = 'opacity 0.8s ease';
                        }, 500);
                    }
                });

                // Create nodes
                nodes.forEach(node => {
                    const nodeEl = document.createElement('div');
                    nodeEl.className = 'node';
                    nodeEl.textContent = node.label;
                    nodeEl.style.left = `${width * node.x / 100}px`;
                    nodeEl.style.top = `${height * node.y / 100}px`;
                    nodeEl.style.background = node.color;
                    nodeEl.style.opacity = '0';
                    nodeEl.style.transform = 'scale(0.5)';

                    container.appendChild(nodeEl);

                    // An
